class Solution:
    def rearrangeArray(self, nums):
        positives = [x for x in nums if x > 0]
        negatives = [x for x in nums if x < 0]
        result = []
        for p, n in zip(positives, negatives):
            result.append(p)
            result.append(n)
        return result

