class Solution:
    def rearrangeArray(self, nums):
        n = len(nums)
        result = [0] * n
        pos_i = 0
        neg_i = 1
        for x in nums:
            if x > 0:
                result[pos_i] = x
                pos_i += 2
            else:
                result[neg_i] = x
                neg_i += 2
        return result

