var rearrangeArray = function(nums) {
    const n = nums.length;
    const result = new Array(n);
    let posI = 0;
    let negI = 1;
    for (const x of nums) {
        if (x > 0) {
            result[posI] = x;
            posI += 2;
        } else {
            result[negI] = x;
            negI += 2;
        }
    }
    return result;
};
